// 环形缓冲区抽象层接口定义（伪代码，非完整实现）
// 展示 ADT 模式：头文件只暴露接口，实现隐藏细节

typedef struct {
    uint8_t  *buffer;          // 环形缓冲区内存
    volatile uint16_t head;    // CPU 写入位置（尾部）
    volatile uint16_t tail;    // DMA 读取位置（头部）
    volatile uint8_t  flags;   // HTF(0x01) | TCF(0x02)
    uint16_t   capacity;       // 缓冲区总容量
} ringbuf_dma_t;

/* 公共接口 */
void ringbuf_init(ringbuf_dma_t *rb, uint8_t *buf, uint16_t size);
int  ringbuf_push(ringbuf_dma_t *rb, uint8_t byte);
int  ringbuf_pop(ringbuf_dma_t *rb, uint8_t *out);
uint16_t ringbuf_count(ringbuf_dma_t *rb);

/* uart_dma_ring.c — UART5 + DMA2 Stream2 循环接收 */
#include <stm32f4xx.h>
#include <string.h>

#define RING_SIZE  256

static uint8_t dma_buf[RING_SIZE] __attribute__((aligned(4)));
static volatile uint16_t tail __attribute__((aligned(2))) = 0;

/* 启动 UART5 + DMA2 Stream 2 循环接收 */
void uart5_dma_rx_start(void) {
    /* 1. 使能 DMA2 时钟（RCC_AHB1ENR bit 22）*/
    RCC->AHB1ENR |= RCC_AHB1ENR_DMA2EN;

    /* 2. 配置 DMA2 Stream 2：UART5_RX → 内存，循环模式 */
    DMA2_Stream2->CR  = 0;                        /* 关闭 DMA 通道 */
    DMA2_Stream2->CR  = DMA_SxCR_MINC |           /* 内存地址递增 */
                        DMA_SxCR_CIRC |            /* 循环模式 */
                        DMA_SxCR_PL_0 |            /* 中等优先级 */
                        DMA_SxCR_DIR_0;            /* 外设→内存 */
    DMA2_Stream2->PAR = (uint32_t)&UART5->DR;      /* 外设地址 = UART_DR */
    DMA2_Stream2->M0AR = (uint32_t)dma_buf;        /* 内存地址 */
    DMA2_Stream2->NDTR = RING_SIZE;                 /* 传输计数 = 256 */

    /* 3. 使能 DMA 半传输中断（HTIE）和传输完成中断（TCIE）*/
    DMA2_Stream2->CR |= DMA_SxCR_HTIE | DMA_SxCR_TCIE;

    /* 4. 配置 NVIC：DMA2 Stream 2 中断优先级 = 2 */
    NVIC_SetPriority(DMA2_Stream2_IRQn, 2);
    NVIC_EnableIRQ(DMA2_Stream2_IRQn);

    /* 5. 使能 UART5 RXNE 中断 + DMA 接收 */
    UART5->CR1 |= USART_CR1_RXNEIE;               /* 使能 RXNE 中断 */
    UART5->CR3 |= USART_CR3_DMAR;                  /* DMA 接收使能 */
    __HAL_UART_ENABLE_DMA(&huart5, UART_DMA_RECEIVE);

    /* 6. 启动 DMA 传输 */
    DMA2_Stream2->CR |= DMA_SxCR_EN;               /* 使能 DMA 通道 */
}

/* DMA2 Stream 2 中断服务函数 */
void DMA2_Stream2_IRQHandler(void) {
    /* 清除 HT 标志（写 1 清零）*/
    if (DMA2_Stream2->ISR & DMA_ISR_HTIF2) {
        DMA2_Stream2->ISR |= DMA_ISR_HTIF2;        /* 清除半传输标志 */
        /* 此时前半部分数据(dma_buf[0..127])可读 */
    }
    /* 清除 TC 标志 */
    if (DMA2_Stream2->ISR & DMA_ISR_TCIF2) {
        DMA2_Stream2->ISR |= DMA_ISR_TCIF2;        /* 清除传输完成标志 */
        /* 此时全部数据(dma_buf[0..255])可读 */
    }
    /* 注意：清除标志必须在读 ISR 之后立即执行，
     * 否则下一次 DMA 传输结束时标志不会被设置 */
}

/* CPU 从环形缓冲区读取一字节，返回 0=成功，-1=空 */
int ringbuf_pop(uint8_t *out) {
    uint16_t current_tail = tail;
    uint16_t current_head = RING_SIZE - DMA2_Stream2->NDTR;

    if (current_tail == current_head) {
        return -1;  /* 缓冲区空 */
    }
    *out = dma_buf[current_tail];
    current_tail = (current_tail + 1) & (RING_SIZE - 1);
    tail = current_tail;
    return 0;
}

/* 正确的环形缓冲区 pop 操作 — 含临界区保护 */
int ringbuf_pop_safe(uint8_t *out) {
    uint16_t current_tail, current_head;

    __disable_irq();                          /* 进入临界区 */
    current_tail = tail;
    current_head = (RING_SIZE - DMA2_Stream2->NDTR) & (RING_SIZE - 1);

    if (current_tail == current_head) {
        __enable_irq();                       /* 退出临界区 */
        return -1;                            /* 缓冲区空 */
    }

    *out = dma_buf[current_tail];
    tail = (current_tail + 1) & (RING_SIZE - 1);
    __enable_irq();                           /* 退出临界区 */
    return 0;
}

/* 关键：NDTR 读取必须在临界区内，
 * 否则 DMA 可能在临界区外修改 NDTR，
 * 导致 current_head 计算错误 */

/* === 重构前：阻塞式 UART 接收 === */
/* 问题：HAL_UART_Receive() 阻塞直到收到指定字节数，
 * 期间 CPU 无法做任何其他工作。如果对方发送间隔不固定，
 * 可能长时间阻塞在 receive 中。 */

void uart_process_old(void) {
    uint8_t byte;
    /* 阻塞等待 — 这是最大的问题 */
    HAL_UART_Receive(&huart5, &byte, 1, HAL_MAX_DELAY);

    /* 协议解析和接收耦合在中断/阻塞调用中 */
    protocol_parse(byte);  /* 如果这里耗时 > 1ms（9600bps），
                             下一个字节到达时 UART 溢出 */
}

/* === 重构后：DMA 环形缓冲区 + 非阻塞处理 === */

/* ringbuf.h — 抽象层接口 */
typedef struct {
    uint8_t  buf[RING_SIZE];
    volatile uint16_t head;
    volatile uint16_t tail;
} ringbuf_t;

extern void  ringbuf_init(ringbuf_t *rb);
extern int   ringbuf_push(ringbuf_t *rb, uint8_t byte);
extern int   ringbuf_pop(ringbuf_t *rb, uint8_t *out);
extern uint16_t ringbuf_count(ringbuf_t *rb);

/* ringbuf.c — 实现 */
void ringbuf_init(ringbuf_t *rb) {
    rb->head = 0;
    rb->tail = 0;
}

int ringbuf_push(ringbuf_t *rb, uint8_t byte) {
    uint16_t next_head = (rb->head + 1) & (RING_SIZE - 1);
    if (next_head == rb->tail) {
        return -1;  /* 缓冲区满 — 丢弃此字节 */
    }
    rb->buf[rb->head] = byte;
    rb->head = next_head;
    return 0;
}

int ringbuf_pop(ringbuf_t *rb, uint8_t *out) {
    if (rb->head == rb->tail) {
        return -1;  /* 缓冲区空 */
    }
    *out = rb->buf[rb->tail];
    rb->tail = (rb->tail + 1) & (RING_SIZE - 1);
    return 0;
}

uint16_t ringbuf_count(ringbuf_t *rb) {
    return (rb->head - rb->tail) & (RING_SIZE - 1);
}

/* main.c — 非阻塞主循环 */
void main_loop(void) {
    uint8_t byte;
    while (1) {
        /* 从环形缓冲区非阻塞读取 */
        if (ringbuf_pop(&uart_rb, &byte) == 0) {
            protocol_parse(byte);  /* 现在可以在这里安全地解析 */
        }
        /* CPU 可以做其他工作：低功耗休眠、看门狗喂狗等 */
        __WFI();
    }
}
